import { createServer } from 'http'
import { parse as parseUrl } from 'url'
import { WebSocketServer } from 'ws'
import type { WebSocket as WsWebSocket } from 'ws'
import next from 'next'
import { Server as SocketIOServer } from 'socket.io'

const dev = process.env.NODE_ENV !== 'production'
const app = next({ dev })
const handle = app.getRequestHandler()

app.prepare().then(() => {
  const httpServer = createServer((req, res) => {
    const parsedUrl = parseUrl(req.url!, true)
    handle(req, res, parsedUrl)
  })

  // ─── Native WebSocket — WebRTC signaling ────────────────────────────────────
  const wss = new WebSocketServer({ noServer: true })

  // roomId -> Map<ws -> {username, peerId}>
  const rooms = new Map<string, Map<WsWebSocket, { username: string; peerId: string }>>()
  const wsPeerId = new Map<WsWebSocket, string>()
  const wsRoomInfo = new Map<WsWebSocket, { roomId: string; username: string; peerId: string }>()

  wss.on('connection', (ws: WsWebSocket, request) => {
    const url = new URL(request.url || '/', `http://${request.headers.host}`)
    const roomId = url.searchParams.get('room') || 'default'
    const username = decodeURIComponent(url.searchParams.get('name') || 'Anonymous')
    const peerId = 'p-' + Math.random().toString(36).slice(2, 10)

    // Register
    wsPeerId.set(ws, peerId)
    wsRoomInfo.set(ws, { roomId, username, peerId })

    if (!rooms.has(roomId)) rooms.set(roomId, new Map())
    rooms.get(roomId)!.set(ws, { username, peerId })

    // Send welcome to the new peer with list of existing peers
    const existingPeers = Array.from(rooms.get(roomId)!.entries())
      .filter(([w]) => w !== ws)
      .map(([, data]) => ({ peerId: data.peerId, username: data.username }))

    ws.send(JSON.stringify({
      type: 'welcome',
      peerId,
      peers: existingPeers,
      userCount: rooms.get(roomId)!.size,
    }))

    // Notify existing peers about the new peer
    broadcast(ws, {
      type: 'peer-joined',
      peerId,
      username,
    })

    ws.on('message', (raw) => {
      try {
        const msg = JSON.parse(raw.toString())

