import mongoose, { Schema, Document, Types } from 'mongoose';
import { IUser } from './user.model';

export interface IStudent extends Document {
  user_id: Types.ObjectId | IUser; // Can be ID or populated User object
  card_id?: string | null;
  profile_created_at?: Date | null;
  email_verified_at?: Date | null;
  lead_manager?: string | null;
  region_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  course_id?: Types.ObjectId | null;
  student_code?: string | null;
  teacher_id?: Types.ObjectId | null;
  balance?: any;
  created_at: Date;
  updated_at: Date;
  is_deleted: boolean;
  deleted_at: Date | null;
  // Merged fields from Enrollment for UI/Tests (Source of truth is CourseStudent)
  status_detail?: string;
}

const StudentSchema = new Schema<IStudent>({
  user_id: { type: Schema.Types.ObjectId, ref: 'Users', required: true, index: true },
  balance: { 
    type: Schema.Types.Decimal128, 
    default: 0,
    get: (v: any) => (v ? parseFloat(v.toString()) : 0)
  },
  card_id: { type: String, default: null },
  profile_created_at: { type: Date, default: null },
  email_verified_at: { type: Date, default: null },
  lead_manager: { type: String, default: null },
  course_id: { type: Schema.Types.ObjectId, ref: 'Courses', default: null },
  license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
  student_code: { type: String, default: null, index: true },
  teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null, index: true },

  // Extension
  region_id: { type: Schema.Types.ObjectId, ref: 'Cities', default: null },
  is_deleted: { type: Boolean, default: false, index: true },
  deleted_at: { type: Date, default: null },

  // Merged fields for UI/Tests (Primary source is CourseStudent)
  status_detail: { type: String, default: 'Chờ KSK' },
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false,
  collection: 'studentinfos'
});

StudentSchema.index({ region_id: 1, created_at: -1 });
StudentSchema.index({ created_at: -1, is_deleted: 1 });
StudentSchema.index({ course_id: 1, created_at: -1 });
StudentSchema.index({ license_category_id: 1, created_at: -1 });

if (mongoose.models.StudentInfos) {
  mongoose.deleteModel('StudentInfos');
}
export const StudentModel = mongoose.model<IStudent>('StudentInfos', StudentSchema, 'studentinfos');
