        action: faker.helpers.arrayElement([ActionType.CREATE, ActionType.UPDATE]),
        entity_type: faker.helpers.arrayElement(entities),
        entity_id: new mongoose.Types.ObjectId().toString(),
        description: `Thực hiện bởi quản trị viên lúc ${new Date().toLocaleTimeString()}`,
        ip_address: faker.internet.ip()
      });
    }

    // Announcements
    await Announcement.create({
      title: 'Thông báo Sát hạch Tháng 5/2026',
      content: 'Trung tâm thông báo lịch thi sát hạch các hạng B1, B2 bắt đầu từ 15/05. Học viên vui lòng hoàn tất học phí.',
      target_group: 'ALL', channels: ['APP', 'SMS'], status: 'SENT'
    });

    // Targeted Notifications
    const randomStudents = await Student.find().limit(50);
    for (const s of randomStudents) {
      await Notification.create({
        title: 'Nhắc nhở học tập',
        body: 'Bạn có buổi học thực hành vào sáng mai. Vui lòng có mặt đúng giờ.',
        receive_id: s.user_id,
        receive_type: 'user',
        is_read: faker.datatype.boolean()
      });
    }

    logger.info('✨ V6 SEED SUCCESSFUL! DATABASE POPULATED WITH 100% COVERAGE. ✨');
    process.exit(0);
  } catch (error) {
    logger.error('❌ V6 SEED ERROR:', error);
    process.exit(1);
  }
};

runV6Seed();
